import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as n,o as i,c as d,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV-toegang tot de site (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Safety/webdav-site-access.md","filePath":"nl-NL/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),r={name:"nl-NL/Safety/webdav-site-access.md"};function o(s,e,b,g,h,p){return i(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="webdav-toegang-tot-de-site-beta" tabindex="-1">WebDAV-toegang tot de site (Beta) <a class="header-anchor" href="#webdav-toegang-tot-de-site-beta" aria-label="Permalink to &quot;WebDAV-toegang tot de site (Beta)&quot;">​</a></h1><p>De WebDAV-instelling onder Beveiliging stelt je ImgBed-site beschikbaar als WebDAV-endpoint.</p><p>Na inschakelen kun je Windows, macOS, mobiele bestandsbeheerders of elke WebDAV-compatibele client gebruiken om ImgBed-bestanden te bekijken, uploaden, verwijderen en beheren alsof het een externe map is.</p><p>Dit is de WebDAV-toegang van de site zelf. Het is iets anders dan het WebDAV-opslagkanaal in Uploadinstellingen. Het uploadkanaal slaat bestanden op in een WebDAV-dienst van derden. Deze instelling laat je ImgBed-site WebDAV-toegang aanbieden aan clients.</p><h2 id="waar-je-dit-configureert" tabindex="-1">Waar je dit configureert <a class="header-anchor" href="#waar-je-dit-configureert" aria-label="Permalink to &quot;Waar je dit configureert&quot;">​</a></h2><p>Open het beheer en ga naar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Beschikbare instellingen:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="wat-deze-functie-doet" tabindex="-1">Wat deze functie doet <a class="header-anchor" href="#wat-deze-functie-doet" aria-label="Permalink to &quot;Wat deze functie doet&quot;">​</a></h2><p>Na inschakelen biedt ImgBed een vaste toegangs-URL:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>Gebruik deze URL om verbinding te maken met je ImgBed-bestandsmap.</p><p>Goede gebruikssituaties:</p><ul><li>ImgBed-bestanden direct vanuit de bestandsbeheerder van je computer bekijken.</li><li>Afbeeldingen naar de WebDAV-map slepen om ze te uploaden.</li><li>ImgBed-mappen ordenen vanuit je lokale bestandsbeheerder.</li><li>WebDAV-compatibele software gebruiken om afbeeldingen te synchroniseren of beheren.</li><li>ImgBed-inhoud openen zonder het beheerpaneel te gebruiken.</li></ul><h2 id="instellingen" tabindex="-1">Instellingen <a class="header-anchor" href="#instellingen" aria-label="Permalink to &quot;Instellingen&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>Schakelt het WebDAV-endpoint in.</p><p>Wanneer dit uit staat, kunnen clients niet via WebDAV verbinden.</p><h3 id="username-en-password" tabindex="-1">Username en Password <a class="header-anchor" href="#username-en-password" aria-label="Permalink to &quot;Username en Password&quot;">​</a></h3><p>Deze gegevens gebruiken WebDAV-clients bij het verbinden.</p><p>Gebruik een aparte WebDAV-gebruikersnaam en wachtwoord. Hergebruik niet je beheerderswachtwoord of uploadwachtwoord.</p><p>Als gebruikersnaam of wachtwoord leeg is, kunnen WebDAV-clients niet goed verbinden.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode bepaalt welke afbeeldings-URL WebDAV-clients bij lezen gebruiken.</p><p>Veelgebruikte keuzes:</p><table tabindex="0"><thead><tr><th>Modus</th><th>Beschrijving</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed kiest op basis van context. Aanbevolen voor normaal gebruik.</td></tr><tr><td>Original</td><td>Geeft voorkeur aan originele afbeeldingen.</td></tr><tr><td>Thumbnail</td><td>Geeft voorkeur aan thumbnails. Handig voor snelle preview.</td></tr></tbody></table><p>Weet je het niet zeker, laat dan <code>Smart loading</code> staan.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Het standaardkanaal wordt gebruikt voor WebDAV-uploads.</p><p>Wanneer je vanuit Windows of een andere client bestanden naar de WebDAV-map kopieert, uploadt ImgBed ze via het geselecteerde standaard uploadkanaal.</p><p>Als er geen standaardkanaal is gekozen, kan bladeren werken, maar uploaden mislukken.</p><h2 id="webdav-gebruiken-in-windows-11" tabindex="-1">WebDAV gebruiken in Windows 11 <a class="header-anchor" href="#webdav-gebruiken-in-windows-11" aria-label="Permalink to &quot;WebDAV gebruiken in Windows 11&quot;">​</a></h2><p>Windows 11 kan WebDAV toevoegen als netwerklocatie.</p><ol><li>Open <code>This PC</code>.</li><li>Kies <code>Add a network location</code>.</li><li>Vul <code>https://your-domain.com/dav</code> in.</li><li>Vul je WebDAV-gebruikersnaam en wachtwoord in wanneer daarom wordt gevraagd.</li><li>Rond de wizard af. De WebDAV-map kan daarna in File Explorer worden geopend.</li></ol><p><img src="'+a+'" alt="WebDAV toevoegen in Windows 11" loading="lazy"></p><p>Na toevoegen verschijnt de WebDAV-map in Windows File Explorer. Je kunt bestanden openen, kopiëren en beheren zoals in een normale map.</p><p><img src="'+t+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="ondersteunde-acties" tabindex="-1">Ondersteunde acties <a class="header-anchor" href="#ondersteunde-acties" aria-label="Permalink to &quot;Ondersteunde acties&quot;">​</a></h2><p>Na een succesvolle WebDAV-verbinding kun je meestal:</p><ul><li>bestanden en mappen bekijken.</li><li>bestanden uploaden.</li><li>mappen maken.</li><li>bestanden of mappen hernoemen.</li><li>bestanden verplaatsen.</li><li>bestanden verwijderen.</li></ul><p>WebDAV is geschikt voor dagelijkse toegang en kleinschalig bestandsbeheer. Gebruik voor grote verplaatsingen, bulkverwijderingen of complexe ordening het beheerpaneel.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Succesvolle WebDAV-verbindingen verschijnen ook onder het WebDAV-tabblad in Login Device Management.</p><p>Je kunt WebDAV-clients daar bekijken en oude apparaten offline forceren wanneer nodig.</p><p>Als je de WebDAV-gebruikersnaam of het wachtwoord wijzigt, moeten oude clients opnieuw inloggen.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-blijft-vragen-om-gebruikersnaam-en-wachtwoord" tabindex="-1">Windows blijft vragen om gebruikersnaam en wachtwoord <a class="header-anchor" href="#windows-blijft-vragen-om-gebruikersnaam-en-wachtwoord" aria-label="Permalink to &quot;Windows blijft vragen om gebruikersnaam en wachtwoord&quot;">​</a></h3><p>Controleer:</p><ul><li>De URL is <code>https://your-domain.com/dav</code>.</li><li>Gebruikersnaam en wachtwoord komen overeen met de WebDAV-instellingen.</li><li>WebDAV is ingeschakeld.</li><li>De site is bereikbaar via HTTPS.</li></ul><h3 id="bladeren-werkt-maar-uploaden-mislukt" tabindex="-1">Bladeren werkt, maar uploaden mislukt <a class="header-anchor" href="#bladeren-werkt-maar-uploaden-mislukt" aria-label="Permalink to &quot;Bladeren werkt, maar uploaden mislukt&quot;">​</a></h3><p>Controleer <code>Default channel</code>.</p><p>WebDAV-uploads hebben een standaard uploadkanaal nodig. Als dit ontbreekt, uitgeschakeld is of verkeerd is ingesteld, kunnen uploads mislukken.</p><h3 id="toegangssnelheid-is-instabiel" tabindex="-1">Toegangssnelheid is instabiel <a class="header-anchor" href="#toegangssnelheid-is-instabiel" aria-label="Permalink to &quot;Toegangssnelheid is instabiel&quot;">​</a></h3><p>WebDAV-prestaties hangen af van client, netwerk, aantal bestanden en standaard uploadkanaal.</p><p>Heeft een map veel bestanden, organiseer ze dan in submappen in plaats van te veel bestanden in één map te bewaren.</p><h2 id="beveiligingsadvies" tabindex="-1">Beveiligingsadvies <a class="header-anchor" href="#beveiligingsadvies" aria-label="Permalink to &quot;Beveiligingsadvies&quot;">​</a></h2><ul><li>Gebruik HTTPS voor WebDAV-toegang.</li><li>Stel een sterk wachtwoord in.</li><li>Deel het WebDAV-wachtwoord niet met mensen die je niet vertrouwt.</li><li>Zet WebDAV uit wanneer je het niet gebruikt.</li><li>Schoon ongebruikte WebDAV-apparaten regelmatig op in Login Device Management.</li></ul><h2 id="bestandsgrootte-bij-webdav-upload" tabindex="-1">Bestandsgrootte bij WebDAV-upload <a class="header-anchor" href="#bestandsgrootte-bij-webdav-upload" aria-label="Permalink to &quot;Bestandsgrootte bij WebDAV-upload&quot;">​</a></h2><p>WebDAV-clients gebruiken niet de chunk-uploadflow van de browseruploadpagina. Gebruik voor bestanden boven de onderstaande aanbevolen limieten liever de webuploadpagina.</p><table tabindex="0"><thead><tr><th>Standaard uploadkanaal</th><th style="text-align:right;">Aanbevolen limiet per WebDAV-bestand</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const k=n(r,[["render",o]]);export{m as __pageData,k as default};
